// Blink LED on pin 13
#define LED_PIN 13
void setup() {
  pinMode(LED_PIN, OUTPUT);
}
void loop() {
  digitalWrite(LED_PIN, HIGH); // ON
  delay(500);
  digitalWrite(LED_PIN, LOW);  // OFF
  delay(500);
}

